def process_sequence(sequence, index=0, seen=None, tree=None):
    if seen is None:
        seen = set()
    if tree is None:
        tree = BinarySearchTree()

    if index >= len(sequence):
        return tree

    char = sequence[index].lower()
    if char not in seen:
        seen.add(char)
        tree.insert(char)

    return process_sequence(sequence, index + 1, seen, tree)

